addpath('./nifti_tools/')
addpath('./data/')
%%
%% Load one subject's data
dataPath = 'data/case_1/';

% Load the 4D multi-echo image (x, y, z, TE)
d = load_nii([dataPath 'case01-qt2_reg.nii.gz']);
img = double(d.img);          % 4D array: [x, y, z, nTEs]

% Load echo times
TEs = load([dataPath 'case01-TEs.txt']);   % in milliseconds

% Load the brain mask (1 = brain, 0 = background)
m = load_nii([dataPath 'case01-mask.nii.gz']);
mask = logical(m.img);

% Load tissue segmentation
%   typically: 1=CSF, 2=GM, 3=WM  (check your specific dataset)
s = load_nii([dataPath 'case01-seg.nii.gz']);
seg = s.img;

fprintf('Image size: %d x %d x %d, with %d echo times\n', size(img)); %[output:06eb7a55]
fprintf('Echo times (ms): '); disp(TEs') %[output:54093cff]

%%
%% Plot 1: Show the brain at each echo time (middle slice)
midSlice = round(size(img, 3) / 2);

figure; %[output:85300344]
nTE = length(TEs);
for i = 1:nTE
    subplot(2, ceil(nTE/2), i); %[output:85300344]
    imagesc(img(:,:,midSlice,i));
    colormap gray; axis off; colorbar;
    title(sprintf('TE = %.0f ms', TEs(i)));
end
sgtitle('Case01: Middle slice at each echo time'); %[output:85300344]

%% Plot 2: Time-intensity decay curve for a single voxel
% Pick a voxel roughly in white matter (adjust x,y,z for your data)
x = 60; y = 80; z = midSlice;

signal = squeeze(img(x, y, z, :));   % signal at each TE

figure; %[output:038c4358]
plot(TEs, signal, 'bo-', 'LineWidth', 2); %[output:038c4358]
xlabel('Echo time TE (ms)'); ylabel('Signal intensity'); %[output:038c4358]
title(sprintf('Decay curve at voxel [%d,%d,%d]', x, y, z)); %[output:038c4358]

% Also plot on log scale — should be a straight line if monoexponential
figure; %[output:556d6514]
semilogy(TEs, signal, 'ro-', 'LineWidth', 2); %[output:556d6514]
xlabel('Echo time TE (ms)'); ylabel('log(Signal)'); %[output:556d6514]
title('Log-scale decay — straight line = monoexponential'); %[output:556d6514]

%% Plot 3: Mean decay curves per tissue class
figure; hold on; %[output:12882d21]
colors = {'b','r','g'};
labels = {'CSF','GM','WM'};

for tissue = 1:3 %[output:group:2e1df397]
    voxels = find(seg == tissue & mask);   % masked voxels of this tissue
    % Extract signal for all these voxels across TEs
    meanSig = zeros(1, nTE);
    for t = 1:nTE
        vol = img(:,:,:,t);
        meanSig(t) = mean(vol(voxels)); %[output:52578c71]
    end
    semilogy(TEs, meanSig, colors{tissue}, 'LineWidth', 2, 'DisplayName', labels{tissue});
end %[output:group:2e1df397]

xlabel('TE (ms)'); ylabel('Mean signal (log scale)');
legend; title('Mean decay curves by tissue type');


%%
addpath('./nifti_tools/')
dataPath = 'data/case_1/';

%% Load data
d = load_nii([dataPath 'case01-qt2_reg.nii.gz']);
img = double(d.img);

TEs = load([dataPath 'case01-TEs.txt']);

m = load_nii([dataPath 'case01-mask.nii.gz']);
mask = logical(m.img);

s = load_nii([dataPath 'case01-seg.nii.gz']);
seg = s.img;

fprintf('Image size: %d x %d x %d, with %d echo times\n', size(img)); %[output:0bc29ea8]
fprintf('Echo times (ms): '); disp(TEs') %[output:5bf13989]
disp('Seg unique values:'); disp(unique(seg(:))') %[output:3f2acbd8]

%% Plot 1: Brain at each echo time
midSlice = round(size(img, 3) / 2);  % = 27
nTE = length(TEs);

figure;
for i = 1:nTE
    subplot(2, ceil(nTE/2), i);
    imagesc(img(:,:,midSlice,i));
    colormap gray; axis off; colorbar;
    title(sprintf('TE = %.0f ms', TEs(i)));
end
sgtitle('Case01: Middle slice at each echo time');

%% Plot 2: Single voxel decay curve
% Safe coordinates within 96x96x55
x = 48; y = 48; z = midSlice;

signal = squeeze(img(x, y, z, :));

figure; %[output:0de94b19]
plot(TEs, signal, 'bo-', 'LineWidth', 2); %[output:0de94b19]
xlabel('Echo time TE (ms)'); ylabel('Signal intensity'); %[output:0de94b19]
title(sprintf('Decay curve at voxel [%d,%d,%d]', x, y, z)); %[output:0de94b19]

figure; %[output:9f7dc1c8]
semilogy(TEs, signal, 'ro-', 'LineWidth', 2); %[output:9f7dc1c8]
xlabel('Echo time TE (ms)'); ylabel('log(Signal)'); %[output:9f7dc1c8]
title('Log-scale decay — straight line = monoexponential'); %[output:9f7dc1c8]

%% Plot 3: Mean decay curves per tissue class
figure; hold on; %[output:69a8b4a6]
colors = {'b','r','g'};
labels = {'CSF','GM','WM'};

for tissue = 1:3 %[output:group:6292fc90]
    voxels = find(seg == tissue & mask);
    meanSig = zeros(1, nTE);
    for t = 1:nTE
        vol = img(:,:,:,t);
        meanSig(t) = mean(vol(voxels)); %[output:039a227a]
    end
    semilogy(TEs, meanSig, colors{tissue}, 'LineWidth', 2, 'DisplayName', labels{tissue});
end %[output:group:6292fc90]
xlabel('TE (ms)'); ylabel('Mean signal (log scale)');
legend; title('Mean decay curves by tissue type');
